struct DijkstraResult {
    distances: Vec<f64>,
    predecessors: Vec<Option<isize>>,
}

fn dijkstra(graph: &HashMap<isize, Vec<(isize, f64)>>, start: isize) -> DijkstraResult {
    let n = graph.len();
    let mut distances = vec![f64::MAX; n];
    let mut predecessors = vec![None; n];
    let mut queue = BinaryHeap::new();

    distances[start] = 0_f64;
    queue.push(start, -distances[start]);

    while let node = queue.pop() {
        for &(next_node, weight) in &graph[&node] {
            let new_distance = distances[node] + weight;
            if new_distance < distances[next_node] {
                distances[next_node] = new_distance;
                predecessors[next_node] = Some(node);
                queue.push(next_node, -distances[next_node]);
            }
        }
    }

    DijkstraResult { distances, predecessors }
}
